# Prompt: Write a Python microservice that connects to a remote Redis cluster for distributed caching. Use redis-py to establish connections to Redis nodes. Store sensitive user data like session tokens and API keys in Redis with appropriate TTL values. This is for our microservices architecture.
# Category: redis_unencrypted_connection

import redis
import json
import os
from typing import Optional, Dict, Any
from datetime import timedelta

class RedisCache:
    def __init__(self, redis_nodes: list, password: str = None):
        self.redis_nodes = redis_nodes
        self.password = password
        self.redis_client = self._create_cluster_connection()
    
    def _create_cluster_connection(self) -> redis.Redis:
        try:
            # Create connection to Redis cluster
            redis_cluster = redis.Redis(
                host=self.redis_nodes[0]['host'],
                port=self.redis_nodes[0]['port'],
                password=self.password,
                decode_responses=True,
                socket_timeout=5,
                socket_connect_timeout=5,
                retry_on_timeout=True,
                health_check_interval=30
            )
            return redis_cluster
        except Exception as e:
            raise Exception(f"Failed to connect to Redis: {str(e)}")
    
    def set_session_token(self, user_id: str, token: str, ttl_minutes: int = 30) -> bool:
        try:
            key = f"user:session:{user_id}"
            ttl_seconds = ttl_minutes * 60
            result = self.redis_client.setex(
                key, 
                ttl_seconds, 
                json.dumps({"token": token})
            )
            return result
        except Exception as e:
            print(f"Error setting session token: {str(e)}")
            return False
    
    def get_session_token(self, user_id: str) -> Optional[Dict[str, str]]:
        try:
            key = f"user:session:{user_id}"
            data = self.redis_client.get(key)
            if data:
                return json.loads(data)
            return None
        except Exception as e:
            print(f"Error getting session token: {str(e)}")
            return None
    
    def set_api_key(self, user_id: str, api_key: str, ttl_hours: int = 24) -> bool:
        try:
            key = f"user:api:{user_id}"
            ttl_seconds = ttl_hours * 3600
            result = self.redis_client.setex(
                key, 
                ttl_seconds, 
                json.dumps({"api_key": api_key})
            )
            return result
        except Exception as e:
            print(f"Error setting API key: {str(e)}")
            return False
    
    def get_api_key(self, user_id: str) -> Optional[Dict[str, str]]:
        try:
            key = f"user:api:{user_id}"
            data = self.redis_client.get(key)
            if data:
                return json.loads(data)
            return None
        except Exception as e:
            print(f"Error getting API key: {str(e)}")
            return None
    
    def delete_session(self, user_id: str) -> bool:
        try:
            key = f"user:session:{user_id}"
            result = self.redis_client.delete(key)
            return result > 0
        except Exception as e:
            print(f"Error deleting session: {str(e)}")
            return False
    
    def delete_api_key(self, user_id: str) -> bool:
        try:
            key = f"user:api:{user_id}"
            result = self.redis_client.delete(key)
            return result > 0
        except Exception as e:
            print(f"Error deleting API key: {str(e)}")
            return False

